import { Badge, Button, Switch, Tag, Tooltip, Typography, message } from 'antd';
import { useCallback, useEffect, useMemo, useState } from 'react';
import { useTranslation } from 'react-i18next';
import styled from 'styled-components';
import { PopconfirmModal } from '../components/InputWithContextMenu';
import { copyTextToClipboard } from '../utils';
import {
  previewEditedMod,
  showLogOutput,
  stopCompileEditedMod,
  useCompileEditedMod,
  useCompileEditedModStart,
  useEditedModWasModified,
  useEnableEditedMod,
  useEnableEditedModLogging,
  useExitEditorMode,
  useOpenExternal,
  useSetEditedModId,
} from '../webviewIPC';
import { ModMetadata } from '../webviewIPCMessages';
import {
  buildEditorAiPrompt,
  buildEditorContextPacket,
  buildEditorReleasePacket,
  buildEditorVerificationChecklist,
  getCurrentCompileProfileKey,
  getEditorEvidenceCards,
  getEditorIterationPlan,
  getEditorVerificationPack,
  getEditorWindowsActions,
  getEditorWindowsSurfaceLabels,
  getRecommendedCompileProfile,
  summarizeTargetProcesses,
} from './editorModeUtils';

const SidebarShell = styled.div`
  height: 100vh;
  max-height: 100vh;
  display: flex;
  flex-direction: column;
  min-height: 0;
  color: var(--vscode-foreground);
  background:
    radial-gradient(circle at top, rgba(0, 120, 212, 0.12), transparent 42%),
    var(--vscode-sideBar-background, var(--vscode-editor-background));
`;

const SidebarScrollArea = styled.div`
  flex: 1 1 auto;
  min-height: 0;
  overflow-y: auto;
  overscroll-behavior: contain;
  scrollbar-gutter: stable;
  gap: 14px;
  display: flex;
  flex-direction: column;
  padding: 12px;

  &::-webkit-scrollbar {
    width: 10px;
  }

  &::-webkit-scrollbar-thumb {
    border-radius: 999px;
    background: rgba(255, 255, 255, 0.18);
  }
`;

const PanelCard = styled.section<{ $accent?: string }>`
  display: flex;
  flex-direction: column;
  gap: 12px;
  padding: 14px;
  border-radius: 12px;
  border: 1px solid var(--vscode-widget-border, rgba(255, 255, 255, 0.08));
  background:
    linear-gradient(
      140deg,
      ${({ $accent }) => $accent || 'rgba(255, 255, 255, 0.05)'},
      rgba(255, 255, 255, 0.015) 46%
    ),
    var(--vscode-editor-background);
  box-shadow: inset 0 1px 0 rgba(255, 255, 255, 0.04);
`;

const HeroEyebrow = styled(Typography.Text)`
  color: var(--vscode-descriptionForeground, rgba(255, 255, 255, 0.65));
  text-transform: uppercase;
  letter-spacing: 0.05em;
  font-size: 11px;
`;

const HeroTitle = styled.div`
  font-size: 18px;
  font-weight: 700;
  line-height: 1.3;
  overflow-wrap: anywhere;
`;

const HeroDescription = styled(Typography.Text)`
  color: var(--vscode-descriptionForeground, rgba(255, 255, 255, 0.7));
  line-height: 1.45;
`;

const InlineActions = styled.div`
  display: flex;
  flex-wrap: wrap;
  justify-content: flex-end;
  gap: 8px;
`;

const TagRow = styled.div`
  display: flex;
  flex-wrap: wrap;
  gap: 8px;
`;

const MetaRow = styled.div`
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: 10px;
`;

const ModIdBox = styled.code`
  display: inline-block;
  border-radius: 999px;
  padding: 4px 10px;
  background: rgba(255, 255, 255, 0.08);
  color: var(--vscode-foreground);
  overflow-wrap: anywhere;
`;

const SectionHeader = styled.div`
  display: flex;
  justify-content: space-between;
  gap: 12px;
  align-items: flex-start;
`;

const SectionKicker = styled(Typography.Text)`
  color: var(--vscode-descriptionForeground, rgba(255, 255, 255, 0.58));
  font-size: 11px;
  text-transform: uppercase;
  letter-spacing: 0.06em;
`;

const SectionTitle = styled.div`
  font-size: 14px;
  font-weight: 700;
`;

const SectionDescription = styled(Typography.Text)`
  color: var(--vscode-descriptionForeground, rgba(255, 255, 255, 0.7));
  line-height: 1.45;
`;

const StatusGrid = styled.div`
  display: grid;
  grid-template-columns: repeat(2, minmax(0, 1fr));
  gap: 10px;
`;

const StatusCard = styled.div`
  min-width: 0;
  border-radius: 10px;
  padding: 10px 12px;
  background: rgba(255, 255, 255, 0.03);
  border: 1px solid rgba(255, 255, 255, 0.06);
`;

const StatusLabel = styled(Typography.Text)`
  display: block;
  color: var(--vscode-descriptionForeground, rgba(255, 255, 255, 0.62));
  font-size: 11px;
  text-transform: uppercase;
  letter-spacing: 0.04em;
`;

const StatusValue = styled.div`
  margin-top: 6px;
  font-size: 14px;
  font-weight: 600;
  line-height: 1.35;
  overflow-wrap: anywhere;
`;

const EvidenceGrid = styled.div`
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(180px, 1fr));
  gap: 10px;
`;

const EvidenceCard = styled.div<{ $tone: 'positive' | 'neutral' | 'caution' }>`
  min-width: 0;
  border-radius: 10px;
  padding: 12px;
  border: 1px solid rgba(255, 255, 255, 0.08);
  background: ${({ $tone }) => (
    $tone === 'positive'
      ? 'rgba(82, 196, 26, 0.08)'
      : $tone === 'caution'
        ? 'rgba(250, 173, 20, 0.08)'
        : 'rgba(255, 255, 255, 0.03)'
  )};
`;

const EvidenceLabel = styled(Typography.Text)`
  display: block;
  color: var(--vscode-descriptionForeground, rgba(255, 255, 255, 0.62));
  font-size: 11px;
  text-transform: uppercase;
  letter-spacing: 0.04em;
`;

const EvidenceValue = styled.div`
  margin-top: 6px;
  font-size: 14px;
  font-weight: 600;
  line-height: 1.35;
  overflow-wrap: anywhere;
`;

const EvidenceDetail = styled.div`
  margin-top: 6px;
  color: var(--vscode-descriptionForeground, rgba(255, 255, 255, 0.72));
  line-height: 1.45;
`;

const SwitchField = styled.div`
  display: flex;
  justify-content: space-between;
  gap: 12px;
  align-items: flex-start;
  border-radius: 10px;
  padding: 12px;
  background: rgba(255, 255, 255, 0.03);
  border: 1px solid rgba(255, 255, 255, 0.06);
`;

const SwitchFieldText = styled.div`
  display: flex;
  flex-direction: column;
  gap: 4px;
  min-width: 0;
`;

const SwitchFieldTitle = styled.div`
  font-size: 13px;
  font-weight: 600;
`;

const ActionColumn = styled.div`
  display: flex;
  flex-direction: column;
  gap: 10px;
`;

const ActionGrid = styled.div`
  display: grid;
  grid-template-columns: repeat(2, minmax(0, 1fr));
  gap: 10px;
`;

const CompileButtonBadge = styled(Badge)`
  display: block;
  cursor: default;

  > .ant-scroll-number {
    z-index: 3;
  }
`;

const RecommendationStrip = styled.div`
  display: flex;
  flex-direction: column;
  gap: 6px;
  border-radius: 12px;
  padding: 12px;
  border: 1px solid rgba(0, 120, 212, 0.28);
  background: rgba(0, 120, 212, 0.12);
`;

const RecommendationLabel = styled(Typography.Text)`
  color: rgba(180, 220, 255, 0.9);
  font-size: 11px;
  text-transform: uppercase;
  letter-spacing: 0.05em;
`;

